sql:
SELECT city_name, population, density
FROM cities
WHERE density > (SELECT AVG(density) FROM cities);

SELECT city_name 
FROM cities 
WHERE population = (SELECT MAX(population) FROM cities);

external_knowledge:
- Typical number of residents: Average Population;
- Big cities on the coasts: San Francisco, Los Angeles, New York;
- Over the last decade: Years between 2010 and 2020;
- More than one million: Average Population > 1,000,000.

sql:
SELECT cities.city_name, states.state_name 
FROM cities 
INNER JOIN states ON cities.state_code = states.state_code;

external_knowledge:
- "Golden State" is a nickname for California;
- "Golden average" refers to the rounded average value;
- "Economic thriving" metaphorically represents the GDP (Gross Domestic Product) of cities;
- "The year of the 21st century's second decade's end" corresponds to the year 2020.

sql:
SELECT city_name, population
FROM cities
ORDER BY population DESC;

SELECT 
    (SELECT AVG(population) FROM cities) AS avg_city_population,
    (SELECT AVG(population / area_sq_km) FROM states) AS avg_state_pop_density;

SELECT city_name, population
FROM cities
WHERE population > (SELECT AVG(population) FROM cities) AND population > 100000;

SELECT AVG(population) AS average_population
FROM cities
WHERE state_code = 'CA' AND county_fips = 1;
